@dataclass
class Document:
    id: str
    content: str
    metadata: Dict[str, Any]
    embedding: Optional[np.ndarray] = None


class SimpleEmbedding:
    def __init__(self, dimension: int = 384):
        self.dimension = dimension
        
    def _text_to_vector(self, text: str) -> np.ndarray:
        text = text.lower()
        words = re.findall(r'\w+', text)
        
        vector = np.zeros(self.dimension)
        for i, word in enumerate(words):
            hash_val = int(hashlib.sha256(word.encode()).hexdigest(), 16)
            for j in range(self.dimension):
                vector[j] += np.sin(hash_val * (j + 1) / self.dimension)
        
        if len(words) > 0:
            vector = vector / len(words)
        
        norm = np.linalg.norm(vector)
        if norm > 0:
            vector = vector / norm
            
        return vector
    
    def embed_text(self, text: str) -> np.ndarray:
        if not isinstance(text, str):
            raise ValueError("Input must be a string")
        if len(text.strip()) == 0:
            raise ValueError("Input text cannot be empty")
        return self._text_to_vector(text)
    
    def embed_batch(self, texts: List[str]) -> List[np.ndarray]:
        return [self.embed_text(text) for text in texts]


class VectorDatabase:
    def __init__(self, db_path: str = "vector_db.sqlite"):
        self.db_path = db_path
        self.embedding_model = SimpleEmbedding()
        self._init_db()
    
    def _init_db(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS documents (
                id TEXT PRIMARY KEY,
                content TEXT NOT NULL,
                metadata TEXT,
                embedding BLOB,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        ''')
        
        conn.commit()
        conn.close()
    
    def _serialize_embedding(self, embedding: np.ndarray) -> bytes:
        return embedding.tobytes()
    
    def _deserialize_embedding(self, data: bytes) -> np.ndarray:
        return np.frombuffer(data, dtype=np.float64)
    
    def add_document(self, doc: Document):
        if not doc.content or not isinstance(doc.content, str):
            raise ValueError("Document content must be a non-empty string")
        
        if not doc.id or not isinstance(doc.id, str):
            raise ValueError("Document ID must be a non-empty string")
        
        if doc.embedding is None:
            doc.embedding = self.embedding_model.embed_text(doc.content)
        
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        try:
            cursor.execute('''
                INSERT OR REPLACE INTO documents (id, content, metadata, embedding)
                VALUES (?, ?, ?, ?)
            ''', (
                doc.id,
                doc.content,
                json.dumps(doc.metadata),
                self._serialize_embedding(doc.embedding)
            ))
            conn.commit()
        except Exception as e:
            conn.rollback()
            raise e
        finally:
            conn.close()
    
    def add_documents(self, docs: List[Document]):
        for doc in docs:
            self.add_document(doc)
    
    def search(self, query: str, top_k: int = 5) -> List[Document]:
        if not isinstance(query, str) or len(query.strip()) == 0:
            raise ValueError("Query must be a non-empty string")
        
        if not isinstance(top_k, int) or top_k <= 0:
            raise ValueError("top_k must be a positive integer")
        
        query_embedding = self.embedding_model.embed_text(query)
        
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        
        cursor.execute('SELECT id, content, metadata, embedding FROM documents')
        rows = cursor.fetchall()
        conn.close()
        
        results = []
        for row in rows:
            doc_id, content, metadata_json, embedding_blob = row
            doc_embedding = self._deserialize_embedding(embedding_blob)
            
            similarity = np.dot(query_embedding, doc_embedding)
            
            results.append({
                'document': Document(
                    id=doc_id,
                    content=content,
                    metadata=json.loads(metadata_json),
                    embedding=doc_embedding
                ),
                'similarity': similarity
            })
        
        results.sort(key=lambda x: x['similarity'], reverse=True)
        
        return [r['document'] for r in results[:top_k]]
    
    def delete_document(self, doc_id: str):
        if not isinstance(doc_id, str) or len(doc_id.strip()) == 0:
            raise ValueError("Document ID must be a non-empty string")
        
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('DELETE FROM documents WHERE id = ?', (doc_id,))
        conn.commit()
        conn.close()
    
    def clear(self):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('DELETE FROM documents')
        conn.commit()
        conn.close()


class DocumentLoader:
    @staticmethod
    def load_from_text_file(file_path: str, chunk_size: int = 1000, overlap: int = 200) -> List[Document]:
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")
        
        if not os.path.isfile(file_path):
            raise ValueError(f"Path is not a file: {file_path}")
        
        file_path = os.path.abspath(file_path)
        
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read()
        
        return DocumentLoader.chunk_text(content, file_path, chunk_size, overlap)
    
    @staticmethod
    def chunk_text(text: str, source: str, chunk_size: int = 1000, overlap: int = 200) -> List[Document]:
        if chunk_size <= overlap:
            raise ValueError("chunk_size must be greater than overlap")
        
        documents = []
        start = 0
        chunk_index = 0
        
        while start < len(text):
            end = start + chunk_size
            chunk = text[start:end]
            
            if len(chunk.strip()) > 0:
                doc_id = hashlib.sha256(f"{source}_{chunk_index}".encode()).hexdigest()[:16]
                
                doc = Document(
                    id=doc_id,
                    content=chunk,
                    metadata={
                        'source': source,
                        'chunk_index': chunk_index,
                        'start_pos': start,
                        'end_pos': end
                    }
                )
                documents.append(doc)
                chunk_index += 1
            
            start = end - overlap
        
        return documents
    
    @staticmethod
    def load_from_directory(directory_path: str, extensions: List[str] = None) -> List[Document]:
        if not os.path.exists(directory_path):
            raise FileNotFoundError(f"Directory not found: {directory_path}")
        
        if not os.path.isdir(directory_path):
            raise ValueError(f"Path is not a directory: {directory_path}")
        
        if extensions is None:
            extensions = ['.txt', '.md', '.json', '.csv']
        
        documents = []
        directory_path = os.path.abspath(directory_path)
        
        for root, _, files in os.walk(directory_path):
            for file in files:
                if any(file.endswith(ext) for ext in extensions):
                    file_path = os.path.join(root, file)
                    try:
                        docs = DocumentLoader.load_from_text_file(file_path)
                        documents.extend(docs)
                    except Exception as e:
                        print(f"Error loading {file_path}: {e}")
        
        return documents


class SimpleLLM:
    def __init__(self, max_tokens: int = 2000):
        self.max_tokens = max_tokens
    
    def generate(self, prompt: str) -> str:
        if not isinstance(prompt, str):
            raise ValueError("Prompt must be a string")
        
        response = f"""Based on the provided context, here is a response to your query:

This is a simulated LLM response. In a production environment, this would be replaced 
with an actual LLM API call (e.g., OpenAI, Anthropic, or a local model).

The system has retrieved relevant documents from the knowledge base and included them 
in the prompt context. The LLM would analyze this context and generate an appropriate 
response based on the information provided.

Query processed at: {datetime.now().isoformat()}
Prompt length: {len(prompt)} characters
"""
        return response


class RAGSystem:
    def __init__(self, db_path: str = "vector_db.sqlite"):
        self.vector_db = VectorDatabase(db_path)
        self.llm = SimpleLLM()
        self.system_prompt = """You are a helpful AI assistant for our company's internal knowledge base.
Your role is to answer questions based on the provided context from company documents.
Always base your answers on the context provided. If the context doesn't contain 
relevant information, clearly state that you don't have enough information to answer."""
    
    def load_documents(self, documents: List[Document]):
        if not isinstance(documents, list):
            raise ValueError("documents must be a list")
        
        self.vector_db.add_documents(documents)
        print(f"Loaded {len(documents)} documents into the knowledge base")
    
    def load_from_file(self, file_path: str):
        documents = DocumentLoader.load_from_text_file(file_path)
        self.load_documents(documents)
    
    def load_from_directory(self, directory_path: str, extensions: List[str] = None):
        documents = DocumentLoader.load_from_directory(directory_path, extensions)
        self.load_documents(documents)
    
    def query(self, user_query: str, top_k: int = 5, include_sources: bool = True) -> Dict[str, Any]:
        if not isinstance(user_query, str) or len(user_query.strip()) == 0:
            raise ValueError("Query must be a non-empty string")
        
        user_query = user_query.strip()
        
        retrieved_docs = self.vector_db.search(user_query, top_k=top_k)
        
        context = self._build_context(retrieved_docs)
        
        prompt = self._build_prompt(user_query, context)
        
        response = self.llm.generate(prompt)
        
        result = {
            'query': user_query,
            'response': response,
            'num_documents_retrieved': len(retrieved_docs)
        }
        
        if include_sources:
            result['sources'] = [
                {
                    'id': doc.id,
                    'content_preview': doc.content[:200] + '...' if len(doc.content) > 200 else doc.content,
                    'metadata': doc.metadata
                }
                for doc in retrieved_docs
            ]
        
        return result
    
    def _build_context(self, documents: List[Document]) -> str:
        if not documents:
            return "No relevant documents found."
        
        context_parts = []
        for i, doc in enumerate(documents, 1):
            source = doc.metadata.get('source', 'Unknown')
            context_parts.append(f"[Document {i} - Source: {source}]\n{doc.content}\n")
        
        return "\n".join(context_parts)
    
    def _build_prompt(self, query: str, context: str) -> str:
        prompt = f"""{self.system_prompt}

CONTEXT:
{context}

USER QUERY: {query}

Please provide a helpful and accurate response based on the context above."""
        
        return prompt
    
    def clear_database(self):
        self.vector_db.clear()
        print("Knowledge base cleared")


